// Archivo inicial trazable para el MVP.
// CALIBRACIÓN 2026-06: se mantienen leyendas cerca de 90 y se bajan jugadores medios para evitar demasiados 80-85.
// IMPORTANTE:
// - Las plantillas, secciones de posición y entrenadores proceden de la web oficial del Athletic Club mediante sourceRefs.
// - Los skills 0-100 son una primera valoración semi-realista y quedan marcados como ratingMethod: "mixed" o "manual_estimate".
// - Los minutos/asistencias por jugador se mantienen en 0 cuando no están verificados todavía. No deben tratarse como dato histórico definitivo.

const STATS_PENDING_NOTE = "Plantilla y categoría posicional verificadas por fuente oficial. Minutos/asistencias/goles individuales pendientes de verificación completa antes de usar como estadística histórica definitiva.";

function makeSkills(primaryPosition: PlayerPosition, overall: number, overrides: Partial<PlayerSeason["skills"]> = {}): PlayerSeason["skills"] {
  const templates: Record<PlayerPosition, PlayerSeason["skills"]> = {
    "POR": {"pace": 45, "shooting": 15, "passing": 55, "dribbling": 35, "defending": 30, "physical": 75, "goalkeeping": 82, "mentality": 78},
    "LD": {"pace": 74, "shooting": 45, "passing": 65, "dribbling": 62, "defending": 75, "physical": 73, "goalkeeping": 0, "mentality": 74},
    "LI": {"pace": 74, "shooting": 45, "passing": 65, "dribbling": 62, "defending": 75, "physical": 73, "goalkeeping": 0, "mentality": 74},
    "CAD": {"pace": 78, "shooting": 58, "passing": 70, "dribbling": 72, "defending": 70, "physical": 75, "goalkeeping": 0, "mentality": 75},
    "CAI": {"pace": 78, "shooting": 58, "passing": 70, "dribbling": 72, "defending": 70, "physical": 75, "goalkeeping": 0, "mentality": 75},
    "DFC": {"pace": 58, "shooting": 35, "passing": 58, "dribbling": 42, "defending": 80, "physical": 82, "goalkeeping": 0, "mentality": 78},
    "MCD": {"pace": 62, "shooting": 55, "passing": 74, "dribbling": 67, "defending": 77, "physical": 76, "goalkeeping": 0, "mentality": 78},
    "MC": {"pace": 65, "shooting": 62, "passing": 78, "dribbling": 72, "defending": 65, "physical": 72, "goalkeeping": 0, "mentality": 78},
    "MP": {"pace": 70, "shooting": 76, "passing": 82, "dribbling": 80, "defending": 50, "physical": 68, "goalkeeping": 0, "mentality": 82},
    "MI": {"pace": 78, "shooting": 67, "passing": 73, "dribbling": 76, "defending": 58, "physical": 70, "goalkeeping": 0, "mentality": 74},
    "MD": {"pace": 78, "shooting": 67, "passing": 73, "dribbling": 76, "defending": 58, "physical": 70, "goalkeeping": 0, "mentality": 74},
    "EI": {"pace": 82, "shooting": 72, "passing": 72, "dribbling": 81, "defending": 48, "physical": 68, "goalkeeping": 0, "mentality": 76},
    "ED": {"pace": 82, "shooting": 72, "passing": 72, "dribbling": 81, "defending": 48, "physical": 68, "goalkeeping": 0, "mentality": 76},
    "DC": {"pace": 70, "shooting": 82, "passing": 62, "dribbling": 68, "defending": 38, "physical": 82, "goalkeeping": 0, "mentality": 80},
    "SD": {"pace": 74, "shooting": 78, "passing": 72, "dribbling": 77, "defending": 45, "physical": 72, "goalkeeping": 0, "mentality": 79},
  };
  const base = { ...templates[primaryPosition] };
  const values = Object.values(base);
  const avg = values.reduce((sum, value) => sum + value, 0) / values.length;
  const offset = overall - avg;
  const adjusted = Object.fromEntries(
    Object.entries(base).map(([key, value]) => [
      key,
      key === "goalkeeping" && primaryPosition !== "POR"
        ? value
        : Math.max(0, Math.min(99, Math.round(value + offset * 0.75))),
    ])
  ) as unknown as PlayerSeason["skills"];
  return { ...adjusted, ...overrides };
}


function normalizePlayerId(value: string): string {
  return value
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_|_$/g, "");
}

