function getTacticalSlotLabelsForPlayer(
  canonicalPlayerId: string,
  _positions: PlayerPosition[]
): PlayerSeason["tacticalSlotLabels"] {
  const explicitLabels = TACTICAL_SLOT_LABELS_BY_CANONICAL_PLAYER_ID[canonicalPlayerId];

  if (explicitLabels && explicitLabels.length > 0) {
    return explicitLabels;
  }

  // Fallback conservador:
  // si no conocemos el perfil fino, no restringimos al jugador.
  // Así evitamos bloquear datos históricos todavía incompletos.
  return undefined;
}

function makePlayer(params: {
  name: string;
  season: SeasonId;
  positions: PlayerPosition[];
  overall: number;
  sourceRefs: string[];
  matches?: number;
  minutes?: number;
  goals?: number;
  assists?: number;
  dataConfidence?: number;
  notes?: string;
  tacticalSlotLabels?: PlayerSeason["tacticalSlotLabels"];
}): PlayerSeason {
  const playerId = params.name
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_|_$/g, "");
  const seasonId = params.season.replace("/", "_");
  const canonicalPlayerId = getCanonicalPlayerId(params.name);
  const primaryPosition = params.positions[0];
  const tacticalSlotLabels =
    params.tacticalSlotLabels ??
    getTacticalSlotLabelsForPlayer(canonicalPlayerId, params.positions);

  return {
    id: `${playerId}_${seasonId}`,
    playerId,
    canonicalPlayerId,
    name: params.name,
    season: params.season,
    positions: params.positions,
    tacticalSlotLabels,
    matches: params.matches ?? 0,
    minutes: params.minutes ?? 0,
    goals: params.goals ?? 0,
    assists: params.assists ?? 0,
    skills: makeSkills(primaryPosition, params.overall),
    overall: params.overall,
    dataConfidence: params.dataConfidence ?? 0.55,
    ratingMethod: "mixed",
    sourceRefs: params.sourceRefs,
    notes: params.notes ?? STATS_PENDING_NOTE,
  };
}

function makeCoach(params: {
  name: string; coachId: string; season: SeasonId; overall: number;
  skills: CoachSeason["skills"]; sourceRefs: string[]; dataConfidence?: number; notes?: string;
}): CoachSeason {
  return {
    id: `${params.coachId}_${params.season.replace("/", "_")}`,
    coachId: params.coachId,
    name: params.name,
    season: params.season,
    skills: params.skills,
    overall: params.overall,
    dataConfidence: params.dataConfidence ?? 0.8,
    ratingMethod: "mixed",
    sourceRefs: params.sourceRefs,
    notes: params.notes,
  };
}

