export function getAthleticSeasonById(season: SeasonId): AthleticSeasonSquad | undefined {
  return ATHLETIC_SEASONS.find((squad) => squad.season === season);
}

export function getAvailableAthleticSeasons(): SeasonId[] {
  return ATHLETIC_SEASONS.map((squad) => squad.season);
}

export function getPlayersBySeason(season: SeasonId): PlayerSeason[] {
  return getAthleticSeasonById(season)?.players ?? [];
}

export function getCoachBySeason(season: SeasonId): CoachSeason | undefined {
  return getAthleticSeasonById(season)?.coach;
}







